import json
with open('/root/.openclaw/openclaw.json') as f:
    data = json.load(f)

# Find telegram config
def find_telegram(obj, path=''):
    if isinstance(obj, dict):
        for k, v in obj.items():
            if 'telegram' in str(k).lower() or 'token' in str(k).lower():
                print(f'{path}.{k}: {str(v)[:80]}')
            find_telegram(v, f'{path}.{k}')
    elif isinstance(obj, list):
        for i, v in enumerate(obj):
            find_telegram(v, f'{path}[{i}]')

